/* --- classification du défaut par SOURCE : Outils / Machine / Opérateur ---
   Chaque nature est rattachée à une source. La source par défaut est
   déduite par mots-clés (ci-dessous), mais peut être RÉASSIGNÉE
   manuellement (⚙️ Gestion → Référentiels) — l'override est persisté.
   Outils  = applicateur / lames / matrice / dénudage / sertissage / joint
   Machine = avance / longueur fil / module coupe / bending / fil abîmé
   Opérateur = erreur humaine : identification, bobine, composant, montage */
const CATS = ['Outils','Machine','Opérateur'];
const CAT_OPERATEUR = ['identification','bobine','composant','mauvais','erreur connexion','erreur de joint','erreur joint'];
const CAT_MACHINE   = ['longueur de fil','module de coupe','bending','endommag','pincé','pince','ondulé','ondule','détorsad','detorsad'];
let CAT_OVERRIDE = lsGet(LS.cat, {});   // { natureMinuscule : 'Outils'|'Machine'|'Opérateur' }
function defectCat(na){
  const low=(na||'').toLowerCase().trim();
  if(CAT_OVERRIDE[low]) return CAT_OVERRIDE[low];
  if(low.startsWith('erreur') || CAT_OPERATEUR.some(k=>low.includes(k))) return 'Opérateur';
  if(CAT_MACHINE.some(k=>low.includes(k))) return 'Machine';
  return 'Outils';
}
function setCat(na,cat){ const k=(na||'').toLowerCase().trim(); if(!k) return; CAT_OVERRIDE[k]=cat; lsSet(LS.cat,CAT_OVERRIDE); }
const CAT_COL={'Outils':'#fb5a6a','Machine':'#38bdf8','Opérateur':'#f7b733'};
const CAT_ICON={'Outils':'🔧','Machine':'⚙️','Opérateur':'👷'};

/* --- type de machine : mapping réel importé (M735 -> CC64), sinon préfixe alpha (M22 -> M) --- */
/* Mapping type de machine INTÉGRÉ (d'après le fichier fourni) — s'applique sans import.
   Un import (Gestion → Référentiels) ou la synchro Firebase le complètent/écrasent par machine. */
const MACH_TYPE_SEED = {
  "M735":"CC64","M729":"CC64","M742":"CC64","M726":"CC64",
  "M70":"THB 804",
  "M166":"K355","M151":"K355","M160":"K355","M157":"K355",
  "M30":"K550","M103":"K550",
  "T39":"K488S","T88":"K488S",
  "T38":"Sigma 688"
};
let MACH_TYPE = lsGet(LS.machtype, {});   // mapping importé/synchronisé (prioritaire sur le seed)
function machineType(ma){
  if(!ma||['Inconnue','NA','—'].includes(ma)) return 'Inconnue';
  const key=String(ma).trim(), up=key.toUpperCase();
  if(MACH_TYPE[key]) return MACH_TYPE[key];
  if(MACH_TYPE[up]) return MACH_TYPE[up];
  if(MACH_TYPE_SEED[key]) return MACH_TYPE_SEED[key];
  if(MACH_TYPE_SEED[up]) return MACH_TYPE_SEED[up];
  const m=key.match(/^[A-Za-z]+/); return m?m[0].toUpperCase():'Autre';
}

/* --- normalisation du client/projet : fusionne les doublons de saisie
   (espaces insecables colles depuis Excel, "RENAULT"/"renault"/"Renault"...) qui,
   sinon, ressortent comme des secteurs distincts dans les graphiques/filtres.
   Les sigles courts tout en majuscules (BMW, VW, PSA...) sont laisses tels quels ;
   une casse deja mixte (ex. "McLaren") n'est pas touchee non plus. */
function normProject(v){
  let s=String(v==null?'':v).replace(/[\u00a0\u200b\u200c\u200d\ufeff]/g,' ').trim().replace(/\s+/g,' ');
  if(!s) return s;
  if(s==='\u2014'||s==='-'||/^non[\s-]?renseign/i.test(s)) return 'Autre'; // "\u2014" (client non renseign\u00e9 \u00e0 la saisie) = m\u00eame cat\u00e9gorie que "Autre"
  return s.split(' ').map(function(w){
    if(!/[A-Za-z\u00c0-\u00ff]/.test(w)) return w;
    var allCaps=(w===w.toUpperCase()), allLower=(w===w.toLowerCase());
    if(allCaps && w.length<=3) return w;
    if(allCaps || allLower) return w.charAt(0).toUpperCase()+w.slice(1).toLowerCase();
    return w;
  }).join(' ');
}
/* --- décoration : champs dérivés pc (source défaut) + mt (type machine) --- */
function decorate(r){ r.pc=defectCat(r.na); r.mt=machineType(r.ma); r.pr=normProject(r.pr); return r; }
DATA.rows.forEach(decorate);

