/* --- ajout idempotent dans un référentiel persistant --- */
function pushRef(arr,key,val){
  val=(val||'').trim(); if(!val) return false;
  if(!arr.some(x=>String(x).toLowerCase()===val.toLowerCase())){ arr.push(val); lsSet(key,arr); return true; }
  return false;
}
function ensureOperator(name){
  name=(name||'').trim(); if(!name) return;
  if(!OPS.some(o=>o.name.toLowerCase()===name.toLowerCase())){ OPS.push({name, hire:''}); lsSet(LS.ops, OPS); }
}

/* --- production journalière (pour PPM mensuel calculé) --- */
let PROD = lsGet(LS.prod, []);   // [{d:'YYYY-MM-DD', q: production_pcs}]
let PRODM = lsGet(LS.prodm, {}); // production par machine (dernier import) { machine: pcs }
let PRODCAO = lsGet(LS.prodcao, {}); // index par n° CAO { cao: {good, pagoda, ma, pr} }
/* date du jour (fuseau local, pas UTC) au format AAAA-MM-JJ — pour préremplir les champs de saisie */
function todayLocal(offsetDays=0){
  const d=new Date(); d.setDate(d.getDate()+offsetDays);
  const p=n=>String(n).padStart(2,'0');
  return `${d.getFullYear()}-${p(d.getMonth()+1)}-${p(d.getDate())}`;
}
/* parseur de date jour/mois tolérant, partagé par tous les imports.
   Convention FR/MA (JJ/MM) appliquée par défaut quand les deux nombres sont ambigus (<=12) ;
   sinon le nombre >12 est reconnu sans ambiguïté comme le jour. */
/* Date locale AAAA-MM-JJ depuis un objet Date, SANS passer par UTC (toISOString décalait
   d'un jour en fuseau UTC+1 — Maroc). On lit les composants locaux tels qu'affichés. */
function ymdLocal(d){ const p=n=>String(n).padStart(2,'0'); return `${d.getFullYear()}-${p(d.getMonth()+1)}-${p(d.getDate())}`; }
/* Quantité entière robuste (pièces) : accepte un nombre, les séparateurs de milliers
   (espace normal/insécable/fine, apostrophe) et la virgule décimale ; arrondit à l'entier. */
function toIntQ(v){
  if(v==null||v==='') return NaN;
  if(typeof v==='number') return isFinite(v)?Math.round(v):NaN;
  let s=String(v).trim().replace(/[\s   ']/g,'');
  if(/^[+-]?\d+,\d+$/.test(s)) s=s.replace(',','.');   // 12,5 -> 12.5
  const n=parseFloat(s.replace(/[^0-9.\-]/g,''));
  return isNaN(n)?NaN:Math.round(n);
}
function parseDMY(s){
  const m=s.match(/^(\d{1,2})[\/.\-](\d{1,2})[\/.\-](\d{2,4})$/);
  if(!m) return null;
  let a=+m[1], b=+m[2], y=(m[3].length===2?('20'+m[3]):m[3]), mo, da;
  if(a>12){ da=a; mo=b; } else if(b>12){ mo=a; da=b; } else { da=a; mo=b; } // défaut JJ/MM
  if(mo<1||mo>12||da<1||da>31) return null;
  return `${y}-${String(mo).padStart(2,'0')}-${String(da).padStart(2,'0')}`;
}
/* parseur de date tolérant : Date, AAAA-MM-JJ, JJ/MM/AAAA, MM/JJ/AAAA (heure ignorée) */
function parseAnyDate(v){
  if(v==null||v==='') return null;
  if(v instanceof Date && !isNaN(v)) return ymdLocal(v);
  const s=String(v).trim().split(/[ T]/)[0];
  let m=s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/); if(m) return `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`;
  return parseDMY(s);
}
// Année de la feuille PPM (File 2) : déduite de la donnée la plus récente du jeu importé, jamais figée en dur
const PPM_YEAR=(DATA.meta&&DATA.meta.dmax)?DATA.meta.dmax.slice(0,4):String(new Date().getFullYear());
function prodByMonth(){ const m=new Map(); PROD.forEach(p=>{const k=(p.d||'').slice(0,7); if(k) m.set(k,(m.get(k)||0)+(+p.q||0));}); return m; }
function defByMonth(){ const m=new Map(); realRows().forEach(r=>{const k=(r.d||'').slice(0,7); if(k) m.set(k,(m.get(k)||0)+(+r.q||0));}); return m; }
/* jours d'un mois ayant une production saisie (>0) */
function prodDaysOfMonth(key){ return new Set(PROD.filter(p=>(p.d||'').slice(0,7)===key && (+p.q)>0).map(p=>p.d)); }
/* défauts enregistrés UNIQUEMENT sur ces jours (null si aucune ligne défaut ces jours-là) */
function defOnProdDays(key){
  const days=prodDaysOfMonth(key); if(!days.size) return null;
  let def=0, has=false;
  realRows().forEach(r=>{ if(days.has(r.d)){ def+=(+r.q||0); has=true; } });
  return has?def:null;
}
/* PPM cohérent : défauts ÷ production sur LES MÊMES JOURS (null si pas de recouvrement) */
function ppmForKey(key){
  const days=prodDaysOfMonth(key); if(!days.size) return null;
  let prod=0; PROD.forEach(p=>{ if(days.has(p.d)) prod+=(+p.q||0); });
  if(prod<=0) return null;
  const def=defOnProdDays(key);
  if(def==null) return null;   // production saisie mais aucun défaut enregistré ces jours-là
  return Math.round(def/prod*1e6);
}
/* PPM pour un préfixe de date : jour (AAAA-MM-JJ), mois (AAAA-MM) ou année (AAAA).
   = défauts ÷ production sur les jours (de cette période) où de la production est saisie. */
function ppmForPrefix(prefix){
  if(!prefix) return null;
  const L=prefix.length;
  const days=new Set(PROD.filter(p=>(+p.q)>0 && (p.d||'').slice(0,L)===prefix).map(p=>p.d));
  if(!days.size) return null;
  let prod=0; PROD.forEach(p=>{ if(days.has(p.d)) prod+=(+p.q||0); });
  if(prod<=0) return null;
  let def=0, has=false;
  realRows().forEach(r=>{ if(days.has(r.d)){ def+=(+r.q||0); has=true; } });
  if(!has) return null;
  return Math.round(def/prod*1e6);
}
/* PPM pour une semaine ISO (clé « AAAA-Wss ») : défauts ÷ production sur les jours de
   cette semaine où de la production est saisie. (la semaine n'est pas un préfixe de date) */
function ppmForWeekKey(key){
  const m=/^(\d{4})-W(\d{1,2})$/.exec(String(key)); if(!m) return null;
  const y=+m[1], w=+m[2];
  const days=new Set();
  PROD.forEach(p=>{ if((+p.q)<=0||!p.d) return; const dt=new Date(p.d+'T00:00:00'); if(!isNaN(dt) && dt.getFullYear()===y && isoWeek(dt)===w) days.add(p.d); });
  if(!days.size) return null;
  let prod=0; PROD.forEach(p=>{ if(days.has(p.d)) prod+=(+p.q||0); });
  if(prod<=0) return null;
  let def=0, has=false;
  realRows().forEach(r=>{ if(days.has(r.d)){ def+=(+r.q||0); has=true; } });
  if(!has) return null;
  return Math.round(def/prod*1e6);
}

function rowsFilteredExcept(exceptKey){
  return DATA.rows.filter(r=>{
    if(!r._u || r._del) return false;
    for(const d of DIMS){
      if(d.key===exceptKey) continue;
      const s=filters[d.key];
      if(s.size && !s.has(r[d.field])) return false;
    }
    return true;
  });
}
function applyFilters(){
  return DATA.rows.filter(r=>{
    if(!r._u || r._del) return false;
    for(const d of DIMS){ const s=filters[d.key]; if(s.size && !s.has(r[d.field])) return false; }
    return true;
  });
}
function distinctCounts(field, rows){
  const m=new Map();
  rows.forEach(r=>{const v=r[field]; m.set(v,(m.get(v)||0)+1);});
  return [...m.entries()].sort((a,b)=>b[1]-a[1]);
}

/* ---------------- FILTER UI ---------------- */
const rail = document.getElementById('filterRail');
const resetBtn = document.getElementById('resetBtn');
DIMS.forEach(d=>{
  if(d.hidden) return;
  const b=document.createElement('button'); b.className='fbtn'; b.dataset.key=d.key;
  b.innerHTML=`<span class="bt">${d.label}</span> <span class="car">▾</span>`;
  const pop=document.createElement('div'); pop.className='pop';
  pop.innerHTML=`<input placeholder="Chercher ${d.label.toLowerCase()}…">
    <div class="poplist"></div>
    <div class="popfoot"><button class="clr">Effacer</button><button class="cls">Fermer</button></div>`;
  b.appendChild(pop);
  rail.insertBefore(b, resetBtn);
  d._btn=b; d._pop=pop; d._list=pop.querySelector('.poplist'); d._search=pop.querySelector('input');

  b.addEventListener('click',e=>{
    if(e.target.closest('.pop')) return;
    const open=pop.classList.contains('show');
    document.querySelectorAll('.pop').forEach(p=>p.classList.remove('show'));
    if(!open){ buildOptions(d); pop.classList.add('show'); d._search.focus(); }
  });
  d._search.addEventListener('input',debounce(()=>buildOptions(d),150));
  pop.querySelector('.clr').addEventListener('click',()=>{filters[d.key].clear();render();buildOptions(d);});
  pop.querySelector('.cls').addEventListener('click',()=>pop.classList.remove('show'));
});
document.addEventListener('click',e=>{ if(!e.target.closest('.fbtn')) document.querySelectorAll('.pop').forEach(p=>p.classList.remove('show')); });

function buildOptions(d){
  const base=rowsFilteredExcept(d.key);
  const opts=distinctCounts(d.field, base);
  // Dimensions temporelles (année / mois / semaine) : ordre chronologique croissant.
  // Les autres restent triées par nombre décroissant (plus impactant en premier).
  if(d.key==='year'||d.key==='month'||d.key==='week') opts.sort((a,b)=>(+a[0]||0)-(+b[0]||0));
  const q=(d._search.value||'').toLowerCase();
  d._list.innerHTML='';
  opts.filter(([v])=>String(d.fmt(v)).toLowerCase().includes(q)).slice(0,300).forEach(([v,c])=>{
    const sel=filters[d.key].has(v);
    const row=document.createElement('div'); row.className='opt'+(sel?' sel':'');
    row.innerHTML=`<span class="ck">${sel?icon('check',12):''}</span><span class="nm">${esc(d.fmt(v))}</span><span class="oc">${fmt(c)}</span>`;
    row.addEventListener('click',()=>{
      if(filters[d.key].has(v)) filters[d.key].delete(v); else filters[d.key].add(v);
      render(); buildOptions(d);
    });
    d._list.appendChild(row);
  });
  if(!d._list.children.length) d._list.innerHTML='<div class="opt" style="cursor:default;color:var(--dim)">Aucun résultat</div>';
}
resetBtn.addEventListener('click',()=>{DIMS.forEach(d=>filters[d.key].clear());render();});

function renderFilterChrome(){
  DIMS.forEach(d=>{
    if(!d._btn) return;
    const n=filters[d.key].size;
    d._btn.classList.toggle('on',n>0);
    let cnt=d._btn.querySelector('.cnt');
    if(n>0){ if(!cnt){cnt=document.createElement('span');cnt.className='cnt';d._btn.querySelector('.bt').after(cnt);} cnt.textContent=n; }
    else if(cnt) cnt.remove();
  });
  // summary tags
  const sm=document.getElementById('summary'); sm.innerHTML='';
  DIMS.forEach(d=>{
    filters[d.key].forEach(v=>{
      const t=document.createElement('span'); t.className='tag';
      t.innerHTML=`${esc(d.label)}: <b>${esc(d.fmt(v))}</b> <span>${icon('close',12)}</span>`;
      t.querySelector('span').addEventListener('click',()=>{filters[d.key].delete(v);render();});
      sm.appendChild(t);
    });
  });
}

