/* ---------------- ALERTE PROACTIVE PPM ---------------- */
/* Bannière visible en haut du tableau de bord dès que le PPM global dépasse la
   cible (au lieu d'attendre que l'utilisateur remarque la pastille du KPI), avec
   option de notification navigateur pour être alerté même onglet en arrière-plan. */
let _ppmNotifyOn=false; try{ _ppmNotifyOn = localStorage.getItem('lwsq_ppmnotify_v1')==='1'; }catch(e){}
let _ppmAlertDismissed=null;   // valeur (arrondie) de PPM pour laquelle la bannière a été masquée
let _ppmWasOver=null;          // état précédent : ne notifier qu'au moment où on bascule en dépassement
let _ppmLastSig=null;          // dernier PPM (réel) affiché dans la bannière
function updatePPMAlert(ppmG,tgt,over){
  const banner=document.getElementById('ppmAlert'); if(!banner) return;
  if(!over){ banner.style.display='none'; _ppmWasOver=false; return; }
  const sig=Math.round(ppmG), gap=Math.round(ppmG-tgt), pct=tgt?Math.round(gap/tgt*100):0;
  _ppmLastSig=sig;
  const t=document.getElementById('ppmAlertTitle'), s=document.getElementById('ppmAlertSub');
  if(t) t.textContent='PPM global au-dessus de la cible';
  if(s) s.textContent=`${fmt(sig)} PPM vs cible ${fmt(tgt)} · +${fmt(gap)} PPM (+${pct}%)`;
  const bell=document.getElementById('ppmAlertBell'); if(bell) bell.classList.toggle('on',_ppmNotifyOn);
  banner.style.display = (_ppmAlertDismissed===sig) ? 'none' : 'flex';
  if(_ppmWasOver===false && _ppmNotifyOn && typeof Notification!=='undefined' && Notification.permission==='granted'){
    try{ new Notification('Quality Cockpit — PPM au-dessus de la cible',{body:`${fmt(sig)} PPM (cible ${fmt(tgt)}) — dépassement de ${fmt(gap)} PPM (+${pct}%)`}); }catch(e){}
  }
  _ppmWasOver=true;
}
(function(){
  const closeBtn=document.getElementById('ppmAlertClose'), bellBtn=document.getElementById('ppmAlertBell');
  if(closeBtn) closeBtn.addEventListener('click',()=>{
    _ppmAlertDismissed=_ppmLastSig;
    document.getElementById('ppmAlert').style.display='none';
  });
  if(bellBtn) bellBtn.addEventListener('click',()=>{
    if(_ppmNotifyOn){
      _ppmNotifyOn=false; try{ localStorage.setItem('lwsq_ppmnotify_v1','0'); }catch(e){}
      bellBtn.classList.remove('on'); toast('Alertes navigateur désactivées');
      return;
    }
    if(typeof Notification==='undefined'){ toast('Notifications non supportées par ce navigateur',true); return; }
    if(Notification.permission==='granted'){
      _ppmNotifyOn=true; try{ localStorage.setItem('lwsq_ppmnotify_v1','1'); }catch(e){}
      bellBtn.classList.add('on'); toast('Alertes navigateur activées 🔔');
    } else if(Notification.permission==='denied'){
      toast('Notifications bloquées — autorise-les dans les réglages du navigateur',true);
    } else {
      Notification.requestPermission().then(p=>{
        if(p==='granted'){ _ppmNotifyOn=true; try{ localStorage.setItem('lwsq_ppmnotify_v1','1'); }catch(e){} bellBtn.classList.add('on'); toast('Alertes navigateur activées 🔔'); }
        else toast('Permission refusée',true);
      });
    }
  });
})();

/* ---------------- KPI + RENDER ---------------- */
/* sparkline SVG (sans Chart.js, suit le thème via la couleur passée) */
function sparkSVG(vals, color){
  if(!vals || vals.length<2) return '';
  const w=120,h=30, mx=Math.max(...vals), mn=Math.min(...vals), rng=(mx-mn)||1;
  const step=w/(vals.length-1);
  const pts=vals.map((v,i)=>[+(i*step).toFixed(1), +(h-2-((v-mn)/rng)*(h-4)).toFixed(1)]);
  const ln='M'+pts.map(p=>p.join(',')).join(' L');
  const ar=`M0,${h} L`+pts.map(p=>p.join(',')).join(' L')+` L${w},${h} Z`;
  return `<svg class="ksp" viewBox="0 0 ${w} ${h}" preserveAspectRatio="none" aria-hidden="true">
    <path d="${ar}" fill="${color}" opacity="0.13"/><path class="ln" d="${ln}" stroke="${color}"/></svg>`;
}
/* delta tendance : compare les n dernières valeurs aux n précédentes */
function trendDelta(vals){
  if(!vals || vals.length<4) return null;
  const n=Math.min(4, Math.floor(vals.length/2));
  const recent=vals.slice(-n).reduce((a,b)=>a+b,0);
  const prior=vals.slice(-2*n,-n).reduce((a,b)=>a+b,0);
  if(!prior) return null;
  return Math.round((recent-prior)/prior*100);
}
/* badge delta — pour des défauts, hausse = mauvais (rouge), baisse = bon (vert) */
function deltaBadge(pct, higherIsBad){
  if(pct===null||pct===undefined) return '';
  if(pct===0) return `<span class="delta flat">${icon('chevronsUpDown',11)} 0%</span>`;
  const up=pct>0, bad = higherIsBad ? up : !up;
  return `<span class="delta ${bad?'up':'down'}">${icon(up?'chevronUp':'chevronDown',11)} ${Math.abs(pct)}%</span>`;
}

/* KPI animés : compte de l'ancienne valeur vers la nouvelle plutôt que
   de basculer instantanément — donne du poids aux chiffres qui bougent. */
const _kpiPrev=[];
const _reduceMotion = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
function animateKPIs(kp){
  const nodes=document.querySelectorAll('#kpis .kv-n');
  nodes.forEach((el,i)=>{
    const target=+kp[i].n;
    if(isNaN(target)){ return; }
    const start=_kpiPrev[i]!=null?_kpiPrev[i]:target;
    _kpiPrev[i]=target;
    if(_reduceMotion || start===target){ el.textContent=fmt(target); return; }
    const t0=performance.now(), dur=600;
    requestAnimationFrame(function step(now){
      const p=Math.min(1,(now-t0)/dur);
      const eased=1-Math.pow(1-p,3);
      el.textContent=fmt(start+(target-start)*eased);
      if(p<1) requestAnimationFrame(step);
    });
  });
}

let _lastReport=null;
function render(){
  recomputeMeta();
  const fr=applyFilters();
  renderFilterChrome();

  // KPIs
  const events=fr.length;
  const qty=fr.reduce((a,r)=>a+r.q,0);
  const avg=events?qty/events:0;
  const sites=new Set(fr.map(r=>r.si)).size;
  const machines=new Set(fr.map(r=>r.ma)).size;
  const natTop=sumBy(fr,'na')[0];
  const tgt=DATA.ppm.ppmTarget;
  // PPM qui SUIT LES FILTRES : défauts de la sélection ÷ production sur ces mêmes jours.
  const _selDays=new Set(fr.map(r=>r.d).filter(Boolean));
  let _totProd=0; PROD.forEach(p=>{ if(_selDays.has(p.d)) _totProd+=(+p.q||0); });
  const _totDef=fr.reduce((a,r)=>a+(+r.q||0),0);
  const ppmG=_totProd>0?Math.round(_totDef/_totProd*1e6):null;
  const ppmState=ppmG==null?'na':(ppmG>tgt?'bad':'ok');
  const MFR=['','Jan','Fév','Mar','Avr','Mai','Juin','Juil','Aoû','Sep','Oct','Nov','Déc'];
  const _selDates=[..._selDays].sort();
  const _pmin=_selDates.length?+_selDates[0].slice(5,7):0, _pmax=_selDates.length?+_selDates[_selDates.length-1].slice(5,7):0;
  const _ppmPeriod=(_pmin&&_pmax)?` (${MFR[_pmin]}${_pmin!==_pmax?'–'+MFR[_pmax]:''})`:'';
  const _ppmFiltered=DIMS.some(d=>filters[d.key].size);
  updatePPMAlert(ppmG,tgt,ppmState==='bad');
  // séries hebdo (sparkline + tendance)
  const wkPairs=[...sumBy(fr,'w')].sort((a,b)=>a[0]-b[0]);
  const wkQty=wkPairs.map(([,v])=>v);
  const wkEvMap=new Map(); fr.forEach(r=>wkEvMap.set(r.w,(wkEvMap.get(r.w)||0)+1));
  const wkEv=[...wkEvMap.entries()].sort((a,b)=>a[0]-b[0]).map(([,c])=>c);
  const qtyDelta=trendDelta(wkQty), evDelta=trendDelta(wkEv);
  const kp=[
    {c:'k-crim',ic:'alertTriangle',l:'Événements défaut',n:events,v:fmt(events),u:'',s:`base terrain · ${(DATA.meta.dmin||'—').slice(0,7)} → ${(DATA.meta.dmax||'—').slice(0,7)} ${deltaBadge(evDelta,true)}`},
    {c:'k-crim',ic:'box',l:'Quantité défaut totale',n:qty,v:fmt(qty),u:'pcs',s:`moy. ${fmt(avg)} pcs / événement ${deltaBadge(qtyDelta,true)}`,extra:sparkSVG(wkQty,C.crimson)},
    {c:ppmState==='bad'?'k-amb':'k-grn',ic:'target',l:(_ppmFiltered?'PPM sélection':'PPM global')+_ppmPeriod,n:ppmG||0,v:ppmG==null?'—':fmt(ppmG),u:ppmG==null?'':'ppm',
      s:ppmG==null?`saisis la production (Gestion → Données) pour calculer le PPM · cible ${fmt(tgt)}`:`<span class="pill ${ppmState}">${icon(ppmState==='bad'?'chevronUp':'chevronDown',11)} ${ppmState==='bad'?'> cible':'≤ cible'}</span> cible ${fmt(tgt)}`},
    {c:'k-grn',ic:'factory',l:'Sites actifs',n:sites,v:sites,u:'',s:_totProd>0?`production saisie : ${fmt(_totProd)} pcs`:`production non saisie`},
    {c:'k-vio',ic:'wrench',l:'Machines impactées',n:machines,v:machines,u:'',s:`sur la sélection courante`},
    {c:'k-amb',ic:'barchart',l:'Nature dominante',n:natTop?natTop[1]:0,v:natTop?fmt(natTop[1]):'0',u:'pcs',s:natTop?natTop[0].slice(0,30):'—'},
  ];
  document.getElementById('kpis').innerHTML=kp.map(k=>`
    <div class="kpi ${k.c}"><div class="kpi-badge">${icon(k.ic,17)}</div><div class="kl">${k.l}</div>
    <div class="kv"><span class="kv-n">${k.v}</span><span class="u">${k.u}</span></div><div class="ks">${k.s}</div>${k.extra||''}</div>`).join('');
  animateKPIs(kp);

  // synthèse exécutive (insight auto-mis à jour)
  const topMach=sumBy(fr,'ma').filter(([k])=>k&&k!=='Inconnue'&&k!=='NA')[0];
  const domSrc=sumBy(fr,'pc')[0];
  const natPct=qty&&natTop?Math.round(natTop[1]/qty*100):0;
  const srcPct=qty&&domSrc?Math.round(domSrc[1]/qty*100):0;
  document.getElementById('synthese').innerHTML=`
    <div class="sy"><span class="sy-ic">${icon('target',18)}</span><div><div class="sy-k">Priorité défaut</div><div class="sy-v">${natTop?natTop[0].slice(0,26):'—'} <small>${natPct}%</small></div></div></div>
    <div class="sy"><span class="sy-ic">${icon('factory',18)}</span><div><div class="sy-k">Machine #1</div><div class="sy-v">${topMach?topMach[0]:'—'} <small>${topMach?fmt(topMach[1])+' pcs':''}</small></div></div></div>
    <div class="sy"><span class="sy-ic">${CAT_ICON[domSrc?domSrc[0]:'Outils']||'🔧'}</span><div><div class="sy-k">Source dominante</div><div class="sy-v">${domSrc?domSrc[0]:'—'} <small>${srcPct}%</small></div></div></div>
    <div class="sy"><span class="sy-ic">${icon('barchart',18)}</span><div><div class="sy-k">PPM global</div><div class="sy-v">${ppmG==null?'—':fmt(ppmG)} <span class="delta ${ppmState==='bad'?'up':'down'}">${ppmG==null?'production non saisie':`${icon(ppmState==='bad'?'chevronUp':'chevronDown',11)} cible ${fmt(tgt)}`}</span></div></div></div>
    <div class="sy"><span class="sy-ic">${icon('trendup',18)}</span><div><div class="sy-k">Tendance défauts</div><div class="sy-v">${qtyDelta===null?'<small>n/a</small>':deltaBadge(qtyDelta,true)+' <small>vs période préc.</small>'}</div></div></div>`;
  // instantané des chiffres clés, réutilisé par "Envoyer le rapport" (e-mail) sans tout recalculer
  _lastReport={events,qty,avg,ppmG,tgt,ppmState,natTop,natPct,topMach,domSrc,srcPct,qtyDelta,
    dmin:DATA.meta.dmin,dmax:DATA.meta.dmax,filters:DIMS.filter(d=>filters[d.key].size).map(d=>`${d.label}: ${[...filters[d.key]].map(v=>d.fmt(v)).join(', ')}`)};

  // Panneau « Pilotage Qualité — Synthèse & détection de dérive » retiré à la demande.

  // en-tête de rapport (impression)
  document.getElementById('ph-period').textContent=`Période : ${DATA.meta.dmin||'—'} → ${DATA.meta.dmax||'—'} · Édité le ${new Date().toLocaleDateString('fr-FR')} · ${fmt(events)} événements · ${fmt(qty)} pcs défaut`;
  const activeF=DIMS.filter(d=>filters[d.key].size).map(d=>`${d.label}: ${[...filters[d.key]].map(v=>d.fmt(v)).join(', ')}`);
  document.getElementById('ph-filters').textContent=activeF.length?('Filtres actifs — '+activeF.join('  ·  ')):'Vue complète (aucun filtre appliqué)';

  // tendance : jour / semaine / mois (selon _trendG)
  renderTrendChart(fr);

  // PPM line — File 2 (Jan..Mai) + tout mois supplémentaire avec production saisie
  const MLAB=['','Jan','Fév','Mar','Avr','Mai','Juin','Juil','Aoû','Sep','Oct','Nov','Déc'];
  // Axe PPM selon la granularité choisie (_ppmG) : jour / mois / année.
  const _RRppm=realRows();
  const pmMap=prodByMonth();
  let allKeys, keyLabel, _ppmTitle;
  if(_ppmG==='d'){
    allKeys=[...new Set(_RRppm.map(r=>r.d).filter(Boolean))].sort();
    if(allKeys.length>60) allKeys=allKeys.slice(-60);
    keyLabel=k=>{const p=String(k).split('-'); return p.length===3?p[2]+'/'+p[1]:k;};
    _ppmTitle='PPM par jour vs cible';
  } else if(_ppmG==='w'){
    allKeys=[...new Set(_RRppm.filter(r=>r.y&&r.w).map(r=>r.y+'-W'+String(r.w).padStart(2,'0')))].sort();
    keyLabel=k=>'S'+(+k.split('-W')[1]);
    _ppmTitle='PPM par semaine vs cible';
  } else if(_ppmG==='y'){
    allKeys=[...new Set(_RRppm.map(r=>(r.d||'').slice(0,4)).filter(Boolean))].sort();
    keyLabel=k=>k;
    _ppmTitle='PPM par année vs cible';
  } else {
    allKeys=[...new Set(_RRppm.map(r=>(r.d||'').slice(0,7)).filter(Boolean))].sort();
    keyLabel=k=>{const [y,m]=k.split('-'); return (MLAB[+m]||k)+" '"+String(y).slice(2);};
    _ppmTitle='PPM par mois vs cible';
  }
  { const _pt=document.getElementById('ppm-title'); if(_pt) _pt.textContent=_ppmTitle; }
  charts.ppm.data.labels=allKeys.map(keyLabel);
  // PPM réel (File 2) : valeurs sur les mois de base, null au-delà
  // Ligne « PPM réel (File 2) » = données de démonstration → retirée.
  // Le PPM affiché provient uniquement des vraies données (ppmCalc = défauts ÷ production saisie).
  const ppmReal=allKeys.map(()=>null);
  // PPM = défauts ÷ production sur les mêmes jours, pour chaque période de l'axe (jour/mois/année)
  const ppmCalc=allKeys.map(k=> _ppmG==='w' ? ppmForWeekKey(k) : ppmForPrefix(k));
  // cible prolongée sur tout l'axe
  charts.ppm.data.datasets[2].data=allKeys.map(()=>tgt);
  charts.ppm.data.datasets[2].label='Cible '+tgt;
  // emphase du/des mois de la sélection (clé AAAA-MM)
  const focusKeys=new Set([...fr].map(r=>(r.d||'').slice(0,7)));
  const ppmNarrowed=filters.week.size>0||filters.month.size>0;
  charts.ppm.data.datasets[0].data=ppmReal;
  charts.ppm.data.datasets[0].pointRadius = ppmNarrowed ? allKeys.map(k=>focusKeys.has(k)?8:0) : 4;
  charts.ppm.data.datasets[0].pointBackgroundColor = ppmNarrowed ? allKeys.map(k=>focusKeys.has(k)?C.crimson:'rgba(251,90,106,.10)') : C.crimson;
  charts.ppm.data.datasets[1].data=ppmCalc;
  charts.ppm.update();
  const ppmSub=document.getElementById('ppm-sub');
  const hasCalc=ppmCalc.some(v=>v!=null);
  const prodMonthsOutside=[...pmMap.keys()].filter(k=>ppmForKey(k)==null);
  if(ppmSub){
    if(ppmNarrowed) ppmSub.textContent='Mois de la sélection mis en évidence';
    else if(hasCalc) ppmSub.textContent=`PPM réel (File 2) + calculé sur ${ppmCalc.filter(v=>v!=null).length} mois saisi(s)`;
    else if(pmMap.size) ppmSub.textContent='Production saisie — le PPM calculé s\u2019affiche dès qu\u2019il y a des défauts sur les mêmes jours';
    else ppmSub.textContent='Source : suivi PPM · saisis la production (⚙️ Gestion)';
  }
  /* --- bandeau de synthèse PPM (lisibilité) --- */
  (function(){
    const has=ppmG!=null;
    const cur=has?Math.round(ppmG):null, gap=has?Math.round(ppmG-tgt):null, over=has&&ppmG>tgt;
    const cCol=over?'var(--crimson,#fb5a6a)':'var(--green,#34d399)';
    const cv=document.getElementById('ppmCurVal'); if(cv){ cv.textContent=has?fmt(cur):'—'; cv.style.color=has?cCol:'var(--mid)'; }
    const tv=document.getElementById('ppmTgtVal'); if(tv){ tv.textContent=fmt(tgt); tv.style.color='var(--green,#34d399)'; }
    const gv=document.getElementById('ppmGapVal'); if(gv){ gv.textContent=has?((gap>0?'+':'')+fmt(gap)):'—'; gv.style.color=has?cCol:'var(--mid)'; }
    const st=document.getElementById('ppmStatus'); if(st){ st.className='ppm-status '+(has?(over?'bad':'good'):''); st.textContent=has?(over?('⚠ '+fmt(Math.abs(gap))+' PPM au-dessus de la cible'):('✓ '+fmt(Math.abs(gap))+' PPM sous la cible')):'Production non saisie — PPM global indisponible'; }
    const mo=document.getElementById('ppmMonths');
    if(mo){
      const moVals=DATA.ppm.months.map((mn,i)=>{ const k=`${PPM_YEAR}-${String(i+1).padStart(2,'0')}`; return {mn, v:ppmForKey(k)}; });
      mo.innerHTML=moVals.map(x=>{
        if(x.v==null) return '<div class="ppm-mo"><div class="mn">'+x.mn+'</div><div class="mv" style="color:var(--muted,#8190a8)">—</div></div>';
        const cls=x.v>tgt?'over':'under', col=x.v>tgt?'var(--crimson,#fb5a6a)':'var(--green,#34d399)';
        return '<div class="ppm-mo '+cls+'"><div class="mn">'+x.mn+'</div><div class="mv" style="color:'+col+'">'+fmt(x.v)+'</div></div>';
      }).join('');
    }
  })();

  // pareto — coloration "vital few" (natures cumulant 80%)
  let par=sumBy(fr,'na');
  if(par.length>22) par=par.slice(0,22);
  const tot=par.reduce((a,[,v])=>a+v,0); let run=0;
  const cumArr=par.map(([,v])=>{run+=v;return tot?run/tot*100:0;});
  const vitalCut=(()=>{const i=cumArr.findIndex(c=>c>=80);return i>=0?i:par.length-1;})();
  charts.pareto.data.labels=par.map(([n])=>n.length>26?n.slice(0,25)+'…':n);
  charts.pareto.data.datasets[0].data=par.map(([,v])=>v);
  charts.pareto.data.datasets[0].backgroundColor=par.map((_,i)=> i<=vitalCut ? C.crimson : 'rgba(147,166,196,.32)');
  charts.pareto.data.datasets[1].data=cumArr.map(c=>+c.toFixed(1));
  charts.pareto._vals=par.map(([n])=>n);
  charts.pareto.update();
  document.getElementById('par-sub').textContent=`${par.length} natures · ${vitalCut+1} en rouge = 80% (vital few) · ⇲ double-clic = filtrer`;

  // pareto CONNEXION — groupé par le champ « cx » (se remplit dès qu'une connexion est saisie)
  (function(){
    const cxRows=fr.filter(r=>{const v=r.cx==null?'':String(r.cx).trim();return v && !['Non renseigné','Inconnue','NA','—'].includes(v);});
    let cxp=sumBy(cxRows,'cx');
    const empty=document.getElementById('cxParEmpty'), sub=document.getElementById('cxpar-sub');
    if(!cxp.length){
      charts.cxpareto.data.labels=[]; charts.cxpareto.data.datasets[0].data=[]; charts.cxpareto.data.datasets[1].data=[]; charts.cxpareto._vals=[]; charts.cxpareto.update();
      if(empty) empty.style.display='block';
      if(sub) sub.textContent='Aucune connexion saisie — renseigne le champ « Connexion » dans les réclamations';
    } else {
      if(empty) empty.style.display='none';
      if(cxp.length>22) cxp=cxp.slice(0,22);
      const t=cxp.reduce((a,[,v])=>a+v,0); let rn=0;
      const cum=cxp.map(([,v])=>{rn+=v;return t?rn/t*100:0;});
      const vc=(()=>{const i=cum.findIndex(c=>c>=80);return i>=0?i:cxp.length-1;})();
      charts.cxpareto.data.labels=cxp.map(([n])=>n.length>26?n.slice(0,25)+'…':n);
      charts.cxpareto.data.datasets[0].data=cxp.map(([,v])=>v);
      charts.cxpareto.data.datasets[0].backgroundColor=cxp.map((_,i)=> i<=vc ? C.crimson : 'rgba(147,166,196,.32)');
      charts.cxpareto.data.datasets[1].data=cum.map(c=>+c.toFixed(1));
      charts.cxpareto._vals=cxp.map(([n])=>n);
      charts.cxpareto.update();
      if(sub) sub.textContent=`${cxp.length} connexion(s) · ${vc+1} en rouge = 80% (vital few)`;
    }
  })();
  update8DLauncherCx(fr);

  // donuts
  const st=sumBy(fr,'si');
  charts.site.data.labels=st.map(([s])=>s);charts.site.data.datasets[0].data=st.map(([,v])=>v);charts.site._vals=st.map(([s])=>s);charts.site.update();
  legendInto('lg-site',st.map(([s])=>s));
  updateSiteWheel(st);
  const pj=sumBy(fr,'pr');
  charts.proj.data.labels=pj.map(([s])=>s);charts.proj.data.datasets[0].data=pj.map(([,v])=>v);charts.proj._vals=pj.map(([s])=>s);charts.proj.update();
  legendInto('lg-proj',pj.map(([s])=>s));
  updateProjWheel(pj);

  // team
  const tm=sumBy(fr,'eq').filter(([k])=>k&&k!=='NA').slice(0,8);
  charts.team.data.labels=tm.map(([s])=>s);charts.team.data.datasets[0].data=tm.map(([,v])=>v);charts.team._vals=tm.map(([s])=>s);charts.team.update();

  // machines top12
  const mc=sumBy(fr,'ma').filter(([k])=>k&&k!=='Inconnue'&&k!=='NA').slice(0,12);
  charts.mach.data.labels=mc.map(([s])=>s);charts.mach.data.datasets[0].data=mc.map(([,v])=>v);charts.mach._vals=mc.map(([s])=>s);charts.mach.update();

  // fournisseur d'outils — uniquement les problèmes SOURCE OUTILS, hors « Non renseigné »
  const toolRows=fr.filter(r=>r.pc==='Outils');
  const tl=sumBy(toolRows,'to').filter(([k])=>k && k!=='Non renseigné' && !BAD_VALS.includes(k)).slice(0,8);
  charts.tool.data.labels=tl.map(([s])=>s);charts.tool.data.datasets[0].data=tl.map(([,v])=>v);charts.tool._vals=tl.map(([s])=>s);charts.tool.update();
  const toolSub=document.getElementById('tool-sub');
  if(toolSub) toolSub.textContent=`Source Outils · hors « Non renseigné » · ${fmt(tl.reduce((a,[,v])=>a+v,0))} pcs`;

  // machine type (top contributeurs)
  const mtt=sumBy(fr,'mt').filter(([k])=>k&&k!=='Inconnue').slice(0,8);
  charts.mtype.data.labels=mtt.map(([s])=>/^[A-Z]{1,6}$/.test(s)?('Type '+s):s);charts.mtype.data.datasets[0].data=mtt.map(([,v])=>v);charts.mtype._vals=mtt.map(([s])=>s);charts.mtype.update();

  // classification par source : Outils / Machine / Opérateur
  const clm=new Map(sumBy(fr,'pc'));
  const clLabels=CATS, clData=clLabels.map(l=>clm.get(l)||0), clTot=clData.reduce((a,b)=>a+b,0);
  const clCol=clLabels.map(l=>CAT_COL[l]);
  charts.cls.data.labels=clLabels;charts.cls.data.datasets[0].data=clData;charts.cls.data.datasets[0].backgroundColor=clCol;charts.cls._vals=clLabels;charts.cls.update();
  document.getElementById('lg-class').innerHTML=clLabels.map((l,i)=>
    `<span class="lg"><i style="background:${clCol[i]}"></i>${CAT_ICON[l]} ${l} · <b style="color:var(--hi)">${fmt(clData[i])}</b> pcs (${clTot?(clData[i]/clTot*100).toFixed(0):0}%)</span>`).join('');
  const domCat=clLabels[clData.indexOf(Math.max(...clData))]||'—';
  document.getElementById('cls-sub').textContent=`Source dominante : ${domCat}`;
  updateClassWheel(clLabels,clData,clCol);

  // Scrap mensuel = quantité défaut RÉELLE par mois (axe dynamique). Cible = valeur perso si définie.
  // → tout se vide dès qu'il n'y a plus de données réelles (plus aucune valeur de démo File 2).
  const _scMLAB=['','Jan','Fév','Mar','Avr','Mai','Juin','Juil','Aoû','Sep','Oct','Nov','Déc'];
  const _scMap=defByMonth();
  const _scKeys=[..._scMap.keys()].sort();
  charts.scrap.data.labels=_scKeys.map(k=>{const[y,m]=k.split('-');return (_scMLAB[+m]||m)+" '"+String(y).slice(2);});
  const scR=_scKeys.map(k=>Math.round(_scMap.get(k)||0));
  const useScT = SCRAP_TGT!=null && +SCRAP_TGT>0;
  const scT = useScT ? _scKeys.map(()=>Math.round(+SCRAP_TGT)) : _scKeys.map(()=>null);
  charts.scrap.data.datasets[0].data=scR;
  charts.scrap.data.datasets[1].data=scT;
  charts.scrap.update();
  const scRsum=scR.reduce((a,v)=>a+(v||0),0), scTsum=scT.reduce((a,v)=>a+(v||0),0);
  const scPct=scTsum?Math.round((scRsum-scTsum)/scTsum*100):0;
  const _scSub=document.getElementById('scrap-sub');
  if(_scSub){
    if(!_scKeys.length) _scSub.textContent='Aucune donnée';
    else if(!useScT) _scSub.innerHTML=`${fmt(scRsum)} pcs rebutées · définis une cible scrap (Gestion → Données)`;
    else _scSub.innerHTML=`${fmt(scRsum)} pcs rebutées vs cible ${fmt(scTsum)} <span style="color:var(--violet)">(perso)</span> · <span class="delta ${scPct<=0?'down':'up'}">${icon(scPct<=0?'chevronDown':'chevronUp',11)} ${Math.abs(scPct)}% ${scPct<=0?'sous cible':'au-dessus'}</span>`;
  }

  // Panneau « Défauts par shift » retiré (champ SHIFT supprimé du formulaire).

  renderHeatmap(fr);
  renderCompare(fr);

  renderTable(fr);
  update8DLauncher(fr);
}

/* Tendance jour/semaine/mois : extraite de render() pour pouvoir être
   redessinée seule (bascule j/s/m) sans repasser par tout le tableau de bord. */
function renderTrendChart(fr){
  const qty=fr.reduce((a,r)=>a+r.q,0);
  const MLBL=['','Jan','Fév','Mar','Avr','Mai','Juin','Juil','Aoû','Sep','Oct','Nov','Déc'];
  let agg, labels, vals, titleTxt, subTxt;
  if(_trendG==='d'){
    let all=[...sumBy(fr,'d')].sort((a,b)=>String(a[0]).localeCompare(String(b[0])));
    const capped=all.length>90; agg=capped?all.slice(-90):all;
    labels=agg.map(([d])=>{ const p=String(d).split('-'); return p.length===3?(p[2]+'/'+p[1]):String(d); });
    const shown=agg.reduce((s,[,v])=>s+(+v||0),0);
    vals=agg.map(([d])=>d); titleTxt='Quantité de défauts par jour';
    subTxt=`${agg.length} jour(s)${capped?' — 90 derniers affichés':''} · ${fmt(shown)} pcs · ⇲ double-clic = filtrer`;
  } else if(_trendG==='m'){
    const mm={}; fr.forEach(r=>{ const k=r.y+'-'+String(r.m).padStart(2,'0'); mm[k]=(mm[k]||0)+(+r.q||0); });
    agg=Object.entries(mm).sort((a,b)=>a[0].localeCompare(b[0]));
    labels=agg.map(([k])=>{ const [y,m]=k.split('-'); return (MLBL[+m]||m)+" '"+String(y).slice(2); });
    vals=agg.map(([k])=>parseInt(k.split('-')[1],10)); titleTxt='Quantité de défauts par mois';
    subTxt=`${agg.length} mois · ${fmt(qty)} pcs · ⇲ double-clic = filtrer`;
  } else {
    agg=[...sumBy(fr,'w')].sort((a,b)=>a[0]-b[0]);
    labels=agg.map(([w])=>'S'+w);
    vals=agg.map(([w])=>w); titleTxt='Quantité de défauts par semaine';
    subTxt=`${agg.length} semaines · ${fmt(qty)} pcs · ⇲ double-clic = filtrer`;
  }
  charts.week.data.labels=labels;
  charts.week.data.datasets[0].data=agg.map(([,v])=>v);
  charts.week._vals=vals;
  charts.week.update();
  const t=document.getElementById('wk-title'); if(t) t.textContent=titleTxt;
  const s=document.getElementById('wk-sub'); if(s) s.textContent=subTxt;
}

/* ---------------- CARTE DE CHALEUR ---------------- */
let heatDim='pc';
const HEAT_LABELS={pc:'source',eq:'équipe',sh:'shift'};
function renderHeatmap(fr){
  document.getElementById('heat-dimname').textContent=HEAT_LABELS[heatDim];
  const weeks=[...new Set(fr.map(r=>r.w))].filter(w=>w!=null).sort((a,b)=>a-b);
  // valeurs de la dimension (lignes) : top 8 par quantité, hors vides
  let dimVals=sumBy(fr.filter(r=>r[heatDim]&&!BAD_VALS.includes(r[heatDim])), heatDim).map(([k])=>k);
  if(heatDim!=='pc') dimVals=dimVals.slice(0,8); else dimVals=CATS.filter(c=>dimVals.includes(c));
  const el=document.getElementById('heat');
  if(!weeks.length||!dimVals.length){ el.innerHTML=`<div class="shift-empty" style="margin:8px 0">Pas assez de données pour cette dimension (${HEAT_LABELS[heatDim]}).</div>`; document.getElementById('heat-scale').innerHTML=''; document.getElementById('heat-sub').textContent=''; return; }
  // matrice valeur[dim][week]
  const mat={}; dimVals.forEach(d=>mat[d]={});
  let mx=0;
  fr.forEach(r=>{ const d=r[heatDim]; if(mat[d]&&r.w!=null){ mat[d][r.w]=(mat[d][r.w]||0)+r.q; if(mat[d][r.w]>mx) mx=mat[d][r.w]; } });
  const cellColor=v=>{ if(!v) return 'transparent'; const t=0.12+0.88*(v/(mx||1)); return `rgba(251,90,106,${t.toFixed(3)})`; };
  // en-tête colonnes
  let html=`<div class="heat-row"><div class="heat-corner"></div>${weeks.map(w=>`<div class="heat-colh">S${w}</div>`).join('')}</div>`;
  dimVals.forEach(d=>{
    const icon=heatDim==='pc'?(CAT_ICON[d]||'')+' ':'';
    html+=`<div class="heat-row"><div class="heat-lbl" title="${esc(d)}">${icon}${esc(d)}</div>${
      weeks.map(w=>{const v=mat[d][w]||0;return `<div class="heat-cell" style="background:${cellColor(v)}" title="S${w} · ${esc(d)} : ${fmt(v)} pcs" tabindex="0" role="img" aria-label="Semaine ${w}, ${esc(d)} : ${fmt(v)} pièces">${v?fmt(v):''}</div>`;}).join('')}</div>`;
  });
  el.innerHTML=html;
  document.getElementById('heat-scale').innerHTML=`<span>0</span><span class="bar"></span><span>${fmt(mx)} pcs</span><span style="margin-left:12px;color:var(--mid)">${dimVals.length} lignes × ${weeks.length} semaines</span>`;
  document.getElementById('heat-sub').textContent=`max ${fmt(mx)} pcs / cellule`;
}

/* ---------------- COMPARATIF MOIS N vs N-1 ---------------- */
const MONTH_FR=['','Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
function renderCompare(fr){
  const box=document.getElementById('cmpBox'), title=document.getElementById('cmp-title');
  const months=[...new Set(fr.map(r=>r.m))].filter(m=>m!=null).sort((a,b)=>a-b);
  if(months.length<2){ title.textContent='Mois N vs N-1'; box.innerHTML=`<div class="cmp-empty">Sélectionne une période couvrant <b>au moins 2 mois</b> pour afficher la comparaison (filtre Mois/Semaine/Année).</div>`; return; }
  const mN=months[months.length-1], mP=months[months.length-2];
  const yN=(fr.find(r=>r.m===mN)||{}).y, yP=(fr.find(r=>r.m===mP)||{}).y;
  title.textContent=`${MONTH_FR[mN]} ${yN||''} vs ${MONTH_FR[mP]} ${yP||''}`;
  const rN=fr.filter(r=>r.m===mN), rP=fr.filter(r=>r.m===mP);
  const qN=rN.reduce((a,r)=>a+r.q,0), qP=rP.reduce((a,r)=>a+r.q,0);
  const eN=rN.length, eP=rP.length;
  const pct=(a,b)=>b?Math.round((a-b)/b*100):null;
  const metric=(k,vN,vP,unit,higherBad=true)=>{
    const d=pct(vN,vP);
    return `<div class="cmp-metric"><div class="cmp-m-k">${k}</div><div class="cmp-m-row">
      <span class="cmp-m-v">${fmt(vN)}${unit?`<span style="font-size:12px;color:var(--mid)"> ${unit}</span>`:''}</span>
      ${deltaBadge(d,higherBad)}</div><div class="cmp-m-prev">préc. ${fmt(vP)}${unit?' '+unit:''}</div></div>`;
  };
  // PPM/scrap si les mois sont dans la plage File 2 (1..5)
  let ppmMetric='';
  const pidxN=mN-1, pidxP=mP-1;
  const yMatchesPpm=String(yN)===PPM_YEAR&&String(yP)===PPM_YEAR;
  if(yMatchesPpm&&pidxN>=0&&pidxN<DATA.ppm.months.length&&pidxP>=0&&pidxP<DATA.ppm.months.length){
    const ppN=DATA.ppm.production[pidxN]?Math.round(DATA.ppm.qty.Total[pidxN]/DATA.ppm.production[pidxN]*1e6):null;
    const ppP=DATA.ppm.production[pidxP]?Math.round(DATA.ppm.qty.Total[pidxP]/DATA.ppm.production[pidxP]*1e6):null;
    if(ppN!=null&&ppP!=null) ppmMetric=metric('PPM (File 2)',ppN,ppP,'ppm',true);
  }
  // top movers : variation de quantité par nature
  const aggN=new Map(sumBy(rN,'na')), aggP=new Map(sumBy(rP,'na'));
  const allNat=new Set([...aggN.keys(),...aggP.keys()]);
  const movers=[...allNat].map(n=>({n,d:(aggN.get(n)||0)-(aggP.get(n)||0)})).filter(m=>m.d!==0);
  const up=movers.filter(m=>m.d>0).sort((a,b)=>b.d-a.d).slice(0,4);
  const down=movers.filter(m=>m.d<0).sort((a,b)=>a.d-b.d).slice(0,4);
  const moverRow=(m,bad)=>`<div class="mover"><span class="mover-n" title="${esc(m.n)}">${esc(m.n.length>34?m.n.slice(0,33)+'…':m.n)}</span><span class="mover-d" style="color:${bad?'var(--crimson)':'var(--green)'}">${m.d>0?'+':''}${fmt(m.d)} pcs</span></div>`;
  box.innerHTML=`
    <div class="cmp-metrics">
      ${metric('Quantité défaut',qN,qP,'pcs',true)}
      ${metric('Événements',eN,eP,'',true)}
      ${metric('Moyenne / événement',Math.round(eN?qN/eN:0),Math.round(eP?qP/eP:0),'pcs',true)}
      ${ppmMetric}
    </div>
    <div class="cmp-movers">
      <div class="cmp-mv-col"><div class="cmp-mv-h" style="color:var(--crimson)">${icon('chevronUp',13)} Plus fortes hausses</div>${up.length?up.map(m=>moverRow(m,true)).join(''):'<div class="cmp-empty">Aucune hausse</div>'}</div>
      <div class="cmp-mv-col"><div class="cmp-mv-h" style="color:var(--green)">${icon('chevronDown',13)} Plus fortes baisses</div>${down.length?down.map(m=>moverRow(m,false)).join(''):'<div class="cmp-empty">Aucune baisse</div>'}</div>
    </div>`;
}

/* ---------------- TABLE ---------------- */
