const XLSX_COLS=[
  {k:'d',t:'Date'},{k:'y',t:'Année'},{k:'m',t:'Mois'},{k:'w',t:'Semaine'},{k:'sh',t:'Shift'},
  {k:'prc',t:'Process'},{k:'si',t:'Site'},{k:'pr',t:'Client'},{k:'eq',t:'Équipe'},
  {k:'ma',t:'Machine'},{k:'mt',t:'Type machine'},{k:'to',t:'Fournisseur outils'},{k:'ou',t:"Nom d'outil"},
  {k:'oud',t:'Description outil'},{k:'out',t:"Type d'outil"},{k:'cx',t:'Connexion'},{k:'cao',t:'N° CAO'},{k:'rep',t:'Repère'},
  {k:'na',t:'Nature de défaut'},{k:'pc',t:'Problème'},{k:'fa',t:'Famille'},
  {k:'op',t:'Opérateur'},{k:'su',t:'Superviseur'},{k:'aql',t:'AQL'},{k:'nb',t:'NB'},
  {k:'bon',t:'Pièces bonnes'},{k:'pag',t:'Pagode'},{k:'ppm',t:'PPM ordre'},{k:'q',t:'Quantité'}
];
let sortK='d',sortDir=-1,tableRows=[];
function chipCls(p){return p==='Stellantis'?'c-st':p==='Renault'?'c-rn':p==='Volvo'?'c-vo':'c-x';}
function renderTable(fr){
  const q=(document.getElementById('tsearch').value||'').toLowerCase();
  tableRows=fr.filter(r=>!q||COLS.some(c=>String(r[c.k]==null?'':r[c.k]).toLowerCase().includes(q)));
  tableRows.sort((a,b)=>{let x=a[sortK],y=b[sortK];if(typeof x==='string'){x=x.toLowerCase();y=String(y==null?'':y).toLowerCase();}return ((x>y?1:x<y?-1:0))*sortDir;});
  document.getElementById('thead').innerHTML=COLS.map(c=>`<th data-k="${c.k}">${c.t} <span class="ar">${sortK===c.k?icon(sortDir>0?'chevronUp':'chevronDown',11):icon('chevronsUpDown',11,'ar-idle')}</span></th>`).join('');
  const slice=tableRows.slice(0,400);
  document.getElementById('tbody').innerHTML=slice.map((r,ri)=>'<tr data-ri="'+ri+'">'+COLS.map(c=>{
    if(c.qty)return `<td class="qty">${fmt(r.q)}</td>`;
    let raw=r[c.k]; let v=esc((raw==null||raw==='')?'—':(c.f?c.f(raw):raw));
    if(c.chip)return `<td><span class="chip ${chipCls(r.pr)}">${v}</span></td>`;
    if(c.pc){const cc=CAT_COL[raw]||'#93a6c4';return `<td><span class="chip" style="background:${cc}22;color:${cc}">${(CAT_ICON[raw]||'')} ${v}</span></td>`;}
    return `<td>${v}</td>`;
  }).join('')+'</tr>').join('');
  document.getElementById('trows').textContent=`${fmt(tableRows.length)} lignes${tableRows.length>400?' (400 affichées)':''} · clic droit sur une ligne : détails / modifier`;
  document.querySelectorAll('#thead th').forEach(th=>th.addEventListener('click',()=>{
    const k=th.dataset.k; if(sortK===k)sortDir*=-1;else{sortK=k;sortDir=1;} renderTable(applyFilters());
  }));
}
document.getElementById('tsearch').addEventListener('input',debounce(()=>renderTable(applyFilters()),200));
document.getElementById('csvBtn').addEventListener('click',()=>{
  /* Export Excel (.xlsx) du tableau tel qu'affiché (filtres + recherche + tri appliqués) */
  if(!tableRows.length){ toast('Aucune ligne à exporter',true); return; }
  const rows=tableRows.map(r=>{ const o={}; XLSX_COLS.forEach(c=>{ o[c.t]=(r[c.k]==null?'':r[c.k]); }); return o; });
  dlXlsx([{name:'Défauts (filtre)',rows}],'cutting_defauts_filtre.xlsx');
});

/* Registre : Importer (Excel/CSV) + Supprimer la sélection courante — pour mettre à jour
   et vérifier les données directement depuis le tableau. */
