/* révèle le champ texte quand "Autre…" est choisi dans un select */
function wireOther(selId){
  const sel=document.getElementById(selId), ni=document.getElementById(selId+'-new');
  if(!sel||!ni) return;
  sel.addEventListener('change',()=>{
    const other=sel.value==='__OTHER__';
    ni.style.display=other?'block':'none';
    if(other) ni.focus(); else { ni.value=''; ni.classList.remove('bad'); }
    sel.classList.remove('bad');
  });
  ni.addEventListener('input',()=>ni.classList.remove('bad'));
}
