/* valeur effective d'un champ (gère selects + champ "Autre") */
function fieldVal(id){
  const el=document.getElementById(id); if(!el) return '';
  if(el.tagName==='SELECT' && el.value==='__OTHER__'){ const ni=document.getElementById(id+'-new'); return ni?ni.value.trim():''; }
  return String(el.value||'').trim();
}
function markBad(id,bad){
  const el=document.getElementById(id); if(el) el.classList.toggle('bad',bad);
  if(el && el.tagName==='SELECT' && el.value==='__OTHER__'){ const ni=document.getElementById(id+'-new'); if(ni) ni.classList.toggle('bad',bad); }
}

function isoWeek(d){
  const t=new Date(Date.UTC(d.getFullYear(),d.getMonth(),d.getDate()));
  const day=(t.getUTCDay()+6)%7;t.setUTCDate(t.getUTCDate()-day+3);
  const firstThu=new Date(Date.UTC(t.getUTCFullYear(),0,4));
  const fday=(firstThu.getUTCDay()+6)%7;firstThu.setUTCDate(firstThu.getUTCDate()-fday+3);
  return 1+Math.round((t-firstThu)/(7*864e5));
}

