  if(!cao){ if(hint){hint.innerHTML='💡 Saisis le <b>N° CAO</b> : si le fichier de production est importé, les <b>pièces bonnes</b> et la <b>pagode</b> se remplissent automatiquement et le <b>PPM = défauts ÷ pièces bonnes × 1 000 000</b>.';hint.style.color='var(--mid)';} caoPPM(); return; }
