/* --- détection du problème prioritaire depuis la sélection --- */
function detectProblem(fr){
  if(!fr.length) return null;
  const byNat=sumBy(fr,'na'); const [nat,qty]=byNat[0];
  const sub=fr.filter(r=>r.na===nat);
  const totalQty=fr.reduce((a,r)=>a+r.q,0);
  const dates=sub.map(r=>r.d).sort();
  const flt=(arr,bad)=>arr.filter(([k])=>k&&!bad.includes(k));
  return {
    nat, qty, occ:sub.length, totalQty, share: totalQty?qty/totalQty*100:0,
    dmin:dates[0], dmax:dates[dates.length-1],
    machines:flt(sumBy(sub,'ma'),['Inconnue','NA']),
    sites:sumBy(sub,'si'),
    teams:flt(sumBy(sub,'eq'),['NA']),
    sups:flt(sumBy(sub,'su'),['Non renseigné']),
    projs:sumBy(sub,'pr'),
    fams:flt(sumBy(sub,'fa'),['—']),
    tools:flt(sumBy(sub,'to'),['Non renseigné']),
  };
}
function update8DLauncher(fr){
  const p=detectProblem(fr), g=id=>document.getElementById(id);
  if(!p){ g('lc-prob').textContent='Aucune donnée sur la sélection'; ['lc-qty','lc-occ','lc-mac','lc-site','lc-share'].forEach(i=>g(i).textContent='—'); return; }
  g('lc-prob').textContent=p.nat;
  g('lc-qty').textContent=fmt(p.qty);
  g('lc-occ').textContent=fmt(p.occ);
  g('lc-mac').textContent=p.machines[0]?p.machines[0][0]:'—';
  g('lc-site').textContent=p.sites[0]?p.sites[0][0]:'—';
  g('lc-share').textContent=p.share.toFixed(1)+'%';
}

/* --- détection de la connexion prioritaire (même logique, groupée par cx) --- */
function detectProblemCx(fr){
  const rows=fr.filter(r=>{const v=r.cx==null?'':String(r.cx).trim();return v && !['Non renseigné','Inconnue','NA','—'].includes(v);});
  if(!rows.length) return null;
  const byCx=sumBy(rows,'cx'); const [cx,qty]=byCx[0];
  const sub=rows.filter(r=>String(r.cx).trim()===cx);
  const totalQty=rows.reduce((a,r)=>a+r.q,0);
  const dates=sub.map(r=>r.d).sort();
  const flt=(arr,bad)=>arr.filter(([k])=>k&&!bad.includes(k));
  return {
    nat:cx, qty, occ:sub.length, totalQty, share: totalQty?qty/totalQty*100:0,
    dmin:dates[0], dmax:dates[dates.length-1],
    machines:flt(sumBy(sub,'ma'),['Inconnue','NA']),
    sites:sumBy(sub,'si'),
    teams:flt(sumBy(sub,'eq'),['NA']),
    sups:flt(sumBy(sub,'su'),['Non renseigné']),
    projs:sumBy(sub,'pr'),
    fams:flt(sumBy(sub,'fa'),['—']),
    tools:flt(sumBy(sub,'to'),['Non renseigné']),
  };
}
function update8DLauncherCx(fr){
  const p=detectProblemCx(fr), g=id=>document.getElementById(id);
  if(!p){ if(g('cx-prob'))g('cx-prob').textContent='Aucune connexion saisie'; ['cx-qty','cx-occ','cx-mac','cx-site','cx-share'].forEach(i=>{if(g(i))g(i).textContent='—';}); return; }
  g('cx-prob').textContent=p.nat;
  g('cx-qty').textContent=fmt(p.qty);
  g('cx-occ').textContent=fmt(p.occ);
  g('cx-mac').textContent=p.machines[0]?p.machines[0][0]:'—';
  g('cx-site').textContent=p.sites[0]?p.sites[0][0]:'—';
  g('cx-share').textContent=p.share.toFixed(1)+'%';
}

