/* --- pré-remplissage depuis la sélection --- */
function setV(key,val){const el=document.querySelector(`[data-8d="${key}"]`); if(el) el.value=(val==null?'':val);}
function prefill8D(p){
  const today=new Date(), iso=todayLocal();
  const seq=String(Math.floor(today.getTime()/1000)%100000).padStart(5,'0');
  setV('ref','8D-'+today.getFullYear()+'-'+seq);
  setV('dopen',iso);
  setV('dtarget',todayLocal(10));
  setV('dclose','');
  const st=document.querySelector('[data-8d="status"]'); if(st) st.value='Ouvert';

  if(!p){
    ['client','part','site','d0_symptom','d0_era','w_quoi','w_qui','w_ou','w_quand','w_comment','w_combien','w_pourquoi','is_quoi_is','is_ou_is','is_quand_is','is_ampleur_is','is_quoi_not','is_ou_not','is_quand_not','is_ampleur_not','why_root','d4_occ','d4_det','d6_before','d6_after','d6_proof','d6_date','d7_note','d8_date','d8_team','d8_summary'].forEach(k=>setV(k,''));
    renderD1(); renderAction([],'d3Rows'); renderAction([],'d5Rows');
    document.getElementById('fishEffect').textContent='—'; renderFish(CAUSE_DEFAULT); renderWhy([]); renderD7([]); calcNPR(); return;
  }
  const machTop=p.machines.slice(0,3).map(m=>m[0]).join(', ')||'—';
  const siteTop=p.sites.slice(0,3).map(s=>s[0]).join(', ')||'—';
  const period=(p.dmin===p.dmax)?p.dmin:(p.dmin+' → '+p.dmax);
  const sup=p.sups[0]?p.sups[0][0]:'—';

  setV('client',p.projs[0]?p.projs[0][0]:'');
  setV('part',p.fams[0]?p.fams[0][0]:'');
  setV('site',siteTop);
  setV('d0_symptom',`Défaut « ${p.nat} » détecté en coupe : ${fmt(p.qty)} pcs sur ${fmt(p.occ)} occurrence(s), période ${period}. Site(s) : ${siteTop}. Machine(s) : ${machTop}.`);
  setV('d0_era',`Isolement des pièces suspectes et information du superviseur (${sup}). Ouverture d'une alerte qualité et arrêt de la production concernée si nécessaire.`);
  renderD1(D1_ROLES.map((r,i)=>({role:r,nom:(i===0&&p.sups[0])?p.sups[0][0]:'',fonction:''})));
  setV('w_quoi',p.nat);
  setV('w_qui',sup!=='—'?sup:'Contrôle coupe');
  setV('w_ou',`${siteTop} — machine(s) ${machTop}`);
  setV('w_quand',period);
  setV('w_comment','Contrôle visuel / autocontrôle en sortie de coupe');
  setV('w_combien',`${fmt(p.qty)} pcs · ${fmt(p.occ)} occurrence(s) · ${p.share.toFixed(1)}% des défauts de la sélection`);
  setV('w_pourquoi','Risque de non-conformité livrée (fonction électrique / sertissage) — défaut critique câblage automobile.');
  setV('is_quoi_is',p.nat); setV('is_ou_is',siteTop+' / '+machTop); setV('is_quand_is',period); setV('is_ampleur_is',`${fmt(p.qty)} pcs (${p.share.toFixed(1)}%)`);
  ['is_quoi_not','is_ou_not','is_quand_not','is_ampleur_not'].forEach(k=>setV(k,''));
  renderAction(CONTAINMENT_LIB.map(a=>({action:a,resp:'',delai:'',statut:'À faire'})),'d3Rows');
  document.getElementById('fishEffect').textContent=`${p.nat} — ${fmt(p.qty)} pcs / ${fmt(p.occ)} occ. · ${machTop}`;
  renderFish(buildCauses(p.nat));
  renderWhy([]); setV('why_root',''); setV('d4_occ',''); setV('d4_det','');
  renderAction(PCA_LIB.map(a=>({action:a,resp:'',delai:'',statut:'À faire'})),'d5Rows');
  setV('d6_before',p.qty); setV('d6_after',''); setV('d6_proof',''); setV('d6_date','');
  const eff=document.querySelector('[data-8d="d6_eff"]'); if(eff) eff.value='À confirmer';
  renderD7([]); setV('d7_note','');
  setV('d8_date',''); setV('d8_team',''); setV('d8_summary','');
  // proposition NPR : occurrence indexée sur la part du Pareto
  document.getElementById('nprS').value=7;
  document.getElementById('nprO').value=p.share>=25?7:p.share>=10?5:3;
  document.getElementById('nprD').value=6;
  calcNPR();
}

/* --- NPR --- */
function calcNPR(){
  const s=+document.getElementById('nprS').value||0,o=+document.getElementById('nprO').value||0,d=+document.getElementById('nprD').value||0;
  const v=s*o*d, el=document.getElementById('nprV'); el.textContent=v;
  el.style.color=v>=200?'var(--crimson)':v>=100?'var(--amber)':'var(--green)';
}
['nprS','nprO','nprD'].forEach(id=>document.getElementById(id).addEventListener('input',calcNPR));

