function seniorityMonths(hire){
  if(!hire) return null;
  const h=new Date(hire+'T00:00:00'); if(isNaN(h)) return null;
  const n=new Date();
  let m=(n.getFullYear()-h.getFullYear())*12+(n.getMonth()-h.getMonth());
  if(n.getDate()<h.getDate()) m--;
  return Math.max(0,m);
}
function seniorityLabel(hire){
  const m=seniorityMonths(hire); if(m==null) return '—';
  const y=Math.floor(m/12), mo=m%12;
  return y? `${m} mois · ${y} an${y>1?'s':''} ${mo} m` : `${m} mois`;
}
