/* ===================== RÔLES QUALITÉ & PERMISSIONS PAR MODULE =====================
   Matrice éditable (Gestion des accès par rôle) : pour chaque rôle qualité, un niveau
   d'accès par module. Admin (et les comptes listés dans ADMIN_EMAILS, ex. Simba) ont
   toujours un accès total et ne passent jamais par cette matrice. */
const QROLE_ORDER=['manager','technicien','tl','utilisateur'];
const QROLE_LABELS={manager:'Manager Qualité',technicien:'Technicien Qualité',tl:'TL Qualité',utilisateur:'Utilisateur'};
const MODULE_ORDER=['dash','claim','gestion','report','pnok','d8report'];
const MODULE_LABELS={dash:'Tableau de bord',claim:'Réclamation',gestion:'Gestion',report:'Rapport',pnok:'Pareto NOK',d8report:'Rapport 8D'};
const MODULE_ICONS={dash:icon('barchart',14),claim:icon('plus',14),gestion:icon('gear',14),report:icon('fileText',14),pnok:icon('barchart',14),d8report:icon('clipboard',14)};
const PERM_ORDER=['none','read','edit'];
const PERM_LABELS={none:'Aucun',read:'Lecture',edit:'Édition'};
const DEFAULT_ROLE_PERMS={
  manager:    {dash:'read', claim:'read', gestion:'none', report:'read', pnok:'none', d8report:'edit'},
  technicien: {dash:'read', claim:'edit', gestion:'none', report:'none', pnok:'none', d8report:'none'},
  tl:         {dash:'edit', claim:'edit', gestion:'edit', report:'edit', pnok:'edit', d8report:'edit'},
  utilisateur:{dash:'read', claim:'edit', gestion:'none', report:'none', pnok:'none', d8report:'none'}
};
function mergeRolePerms(saved){
  const out={};
  QROLE_ORDER.forEach(r=>{ out[r]=Object.assign({}, DEFAULT_ROLE_PERMS[r], (saved&&saved[r])||{}); });
  return out;
}
let ROLE_PERMS = mergeRolePerms(lsGet(LS.roleperms, null));

function computeModulePerm(key, isAdmin, myAccount){
  if(isAdmin) return 'edit';
  const qrole=(myAccount && myAccount.qrole) || 'utilisateur';
  const row=ROLE_PERMS[qrole]||DEFAULT_ROLE_PERMS.utilisateur;
  return row[key]||'none';
}
/* Applique la visibilité des boutons/écrans selon les permissions du compte connecté.
   Appelée à chaque changement d'état d'accès (connexion, rôle modifié, matrice modifiée). */
function applyAccessGates(){
  const isAdmin=!!window._isAdmin, myAccount=window._myAccount||null;
  const dash=computeModulePerm('dash',isAdmin,myAccount);
  const claim=computeModulePerm('claim',isAdmin,myAccount);
  const gestion=computeModulePerm('gestion',isAdmin,myAccount);
  const report=computeModulePerm('report',isAdmin,myAccount);
  const pnok=computeModulePerm('pnok',isAdmin,myAccount);
  const d8report=computeModulePerm('d8report',isAdmin,myAccount);

  const wrap=document.querySelector('.wrap');
  if(wrap) wrap.style.display = dash==='none' ? 'none' : '';
  let noAccessMsg=document.getElementById('noAccessMsg');
  if(dash==='none'){
    if(!noAccessMsg){
      noAccessMsg=document.createElement('div'); noAccessMsg.id='noAccessMsg';
      noAccessMsg.style.cssText='max-width:520px;margin:15vh auto;text-align:center;padding:30px;color:var(--mid);font-size:15px';
      noAccessMsg.innerHTML=`${icon('lock',16)} Accès non autorisé pour ton rôle.<br>Contacte un administrateur si tu penses que c’est une erreur.`;
      document.body.appendChild(noAccessMsg);
    }
  } else if(noAccessMsg){ noAccessMsg.remove(); }

  const openAdd=document.getElementById('openAdd'); if(openAdd) openAdd.style.display = claim==='edit' ? '' : 'none';
  const openMg=document.getElementById('openMg'); if(openMg) openMg.style.display = gestion==='edit' ? '' : 'none';
  const printReport=document.getElementById('printReport'); if(printReport) printReport.style.display = report==='none' ? 'none' : '';
  const emailReportBtn=document.getElementById('emailReport'); if(emailReportBtn) emailReportBtn.style.display = report==='none' ? 'none' : '';
  const rmEdit=document.getElementById('rm-edit'); if(rmEdit) rmEdit.style.display = dash==='edit' ? '' : 'none';
  const rmDel=document.getElementById('rm-del'); if(rmDel) rmDel.style.display = dash==='edit' ? '' : 'none';
  const nokBtn=document.getElementById('nokBtn3'); if(nokBtn) nokBtn.style.display = pnok==='none' ? 'none' : '';
  const d8Print=document.getElementById('d8Print'); if(d8Print) d8Print.style.display = d8report==='none' ? 'none' : '';
}
/* Rendu de la table éditable (modale Comptes & accès) — lecture seule pour les non-admins */
const PERM_ICONS={none:'🚫',read:'👁',edit:'✏️'};
function renderRolePerms(){
  const tbody=document.getElementById('rolePermsBody'); if(!tbody) return;
  const thead=document.getElementById('rolePermsHead');
  if(thead) thead.innerHTML='<th>Rôle \\ Module</th>'+MODULE_ORDER.map(m=>'<th>'+MODULE_ICONS[m]+' '+esc(MODULE_LABELS[m])+'</th>').join('');
  const editable=!!window._isSuperAdmin;
  tbody.innerHTML=QROLE_ORDER.map(r=>{
    const row=ROLE_PERMS[r]||DEFAULT_ROLE_PERMS[r];
    return '<tr><th>'+esc(QROLE_LABELS[r])+'</th>'+MODULE_ORDER.map(m=>{
      const lvl=row[m]||'none';
      const opts=PERM_ORDER.map(p=>'<option value="'+p+'"'+(p===lvl?' selected':'')+'>'+PERM_ICONS[p]+' '+PERM_LABELS[p]+'</option>').join('');
      return '<td><select class="permsel '+lvl+'"'+(editable?' data-permcell="'+r+':'+m+'"':' disabled')+'>'+opts+'</select></td>';
    }).join('')+'</tr>';
  }).join('');
}
document.getElementById('rolePermsBody')?.addEventListener('change',e=>{
  const sel=e.target.closest('[data-permcell]'); if(!sel||!window._isSuperAdmin) return;
  const [r,m]=sel.getAttribute('data-permcell').split(':');
  const next=sel.value;
  ROLE_PERMS={...ROLE_PERMS,[r]:{...ROLE_PERMS[r],[m]:next}};
  lsSet(LS.roleperms, ROLE_PERMS);
  renderRolePerms();
  applyAccessGates();
});
/* ===================== FIN RÔLES & PERMISSIONS ===================== */

/* ===================== FIREBASE · SYNCHRONISATION TEMPS RÉEL =====================
   Stockage partagé multi-postes (Realtime Database · europe-west1).
   Sécurité : authentification e-mail / mot de passe. ATTENTION — la règle RTDB actuelle
   { ".read":"auth!=null", ".write":"auth!=null" } autorise TOUT utilisateur connecté à
   écrire n'importe où, y compris sous /accounts : les vérifications _isAdmin ci-dessous
   ne sont que du confort d'UI côté client et ne bloquent pas un appel direct au SDK
   (ex. firebase.database().ref('accounts/UID/role').set('admin') depuis la console du
   navigateur). Pour une vraie séparation admin/utilisateur, remplacer la règle par :
     {
       "rules": {
         "cockpit": { ".read": "auth != null", ".write": "auth != null" },
         "accounts": {
           ".read": "auth != null",
           "$uid": {
             ".write": "auth != null && (root.child('accounts').child(auth.uid).child('role').val() === 'admin' || (!data.exists() && $uid === auth.uid))"
           }
         }
       }
     }
   Avec cette règle, un compte ne peut plus s'auto-promouvoir admin — seule la création
   initiale de SON PROPRE compte (self-service, à la première connexion, rôle 'utilisateur'
   par défaut) reste permise ; toute modification ultérieure (rôle, désactivation, suppression)
   exige d'être déjà admin. Couvre aussi le tout premier compte (bootstrap) : à ce moment
   /accounts/$uid n'existe pas encore, donc la même clause d'auto-création s'applique.
   ⚠️ Cette règle vit dans la console Firebase (Database → Rules), pas dans ce fichier —
   il faut la coller et la publier manuellement là-bas pour qu'elle prenne effet.
   Résilience : le cache localStorage existant est conservé ; l'app reste utilisable
   hors-ligne (les écritures sont mises en file et synchronisées à la reconnexion).
   Intégration non intrusive : toutes les sauvegardes passent déjà par lsSet/lsDel,
   désormais répliqués vers le cloud (write-through) ; chaque clé est écoutée en
   temps réel et réinjectée dans les variables + render() à toute modification distante. */
(function(){
  const firebaseConfig = {
    apiKey: "AIzaSyAQvekutVRuNfVPFEnODUMu4Mv9nevFlVs",
    authDomain: "qualiter-af6d3.firebaseapp.com",
    databaseURL: "https://qualiter-af6d3-default-rtdb.europe-west1.firebasedatabase.app",
    projectId: "qualiter-af6d3",
    storageBucket: "qualiter-af6d3.firebasestorage.app",
    messagingSenderId: "571290924932",
    appId: "1:571290924932:web:29ef54b8a4b698eb4acfd1",
    measurementId: "G-PFYPG23JY2"
  };
  // Clés répliquées vers le cloud (le thème reste propre à chaque poste)
  const FB_KEYS = [LS.claims, LS.sups, LS.ops, LS.nat, LS.fam, LS.tools, LS.cat, LS.prod, LS.ppmtgt, LS.scraptgt, LS.prodm, LS.prodcao, LS.machtype, LS.edits, LS.roleperms, LS.audit, LS.d8archive, LS.qrqc];
  window._FB_SYNCKEYS = new Set(FB_KEYS);

  const $f = id => document.getElementById(id);
  function _fbErr(t){ const e=$f('fbErr'); if(e){ e.textContent=t||''; e.style.display=t?'block':'none'; } }
  function _setDot(ok){ const d=$f('fbDot'); if(d) d.style.background = ok?'#34d399':'#f87171'; const t=$f('fbDotT'); if(t) t.textContent = ok?'CLOUD · OK':'LOCAL'; const w=d&&d.parentNode; if(w) w.title = ok?'Cloud connecté · synchronisation temps réel':'Hors-ligne · cache local'; }
  // Realtime Database sérialise un tableau devenu "à trous" (élément supprimé au milieu) en objet {index: valeur} :
  // reconvertit ce cas en tableau au lieu de le perdre silencieusement.
  function toArr(val){
    if(Array.isArray(val)) return val;
    if(val && typeof val==='object') return Object.keys(val).sort((a,b)=>(+a)-(+b)).map(k=>val[k]);
    return [];
  }
  function _degradeLocal(){ const o=$f('fbLogin'); if(o) o.style.display='none'; _setDot(false); }

  // SDK indisponible (réseau) → on bascule en mode local pur plutôt que de bloquer l'outil
  if(typeof firebase==='undefined'){ _degradeLocal(); return; }

  try{ firebase.initializeApp(firebaseConfig); }catch(e){}
  const db = firebase.database();
  const auth = firebase.auth();
  window._db = db;
  try{ auth.setPersistence(firebase.auth.Auth.Persistence.LOCAL); }catch(e){}
  try{ db.ref('.info/connected').on('value', s=>{ if(window._fbReady) _setDot(!!s.val()); }); }catch(e){}

  // Application d'une mise à jour distante : maj cache + variable + rendu
  function applyRemote(key, val){
    try{ localStorage.setItem(key, JSON.stringify(val)); }catch(e){}
    if(key===LS.audit){
      // simple journal, pas de variable en mémoire à resynchroniser : on rafraîchit juste l'onglet s'il est ouvert
      try{ if(typeof _mgTab!=='undefined' && _mgTab==='audit') renderMgTab('audit'); }catch(e){}
      return;
    }
    if(key===LS.d8archive){
      try{ renderD8Trend(); }catch(e){}
      return;
    }
    if(key===LS.qrqc){
      QRQC = toArr(val);
      try{ renderQRQC(); }catch(e){}
      return;
    }
    switch(key){
      case LS.prod:     PROD = toArr(val); break;
      case LS.prodm:    PRODM = (val && typeof val==='object')?val:{}; break;
      case LS.prodcao:  PRODCAO = (val && typeof val==='object')?val:{}; break;
      case LS.ops:      OPS = toArr(val); break;
      case LS.sups:     SUPS = (val==null)?SUPS:toArr(val); break;
      case LS.nat:      NAT_EXTRA = toArr(val); break;
      case LS.fam:      FAM_EXTRA = toArr(val); break;
      case LS.tools:    TOOL_EXTRA = toArr(val); break;
      case LS.cat:      CAT_OVERRIDE = (val && typeof val==='object')?val:{}; DATA.rows.forEach(decorate); break;
      case LS.machtype: MACH_TYPE = (val && typeof val==='object')?val:{}; DATA.rows.forEach(decorate); break;
      case LS.ppmtgt:   DATA.ppm.ppmTarget = (+val) || PPM_TGT_ORIG; break;
      case LS.scraptgt: SCRAP_TGT = (val==null? null : val); break;
      case LS.claims:
        for(let i=DATA.rows.length-1;i>=0;i--){ if(DATA.rows[i] && DATA.rows[i]._u) DATA.rows.splice(i,1); }
        toArr(val).forEach(rec=>{ rec._u=1; DATA.rows.push(decorate(rec)); });
        break;
      case LS.edits:
        ROW_EDITS = (val && typeof val==='object')?val:{};
        try{ applyRowEdits(); }catch(e){}
        break;
      case LS.roleperms:
        ROLE_PERMS = mergeRolePerms(val);
        try{ renderRolePerms(); }catch(e){}
        try{ applyAccessGates(); }catch(e){}
        break;
    }
    try{ render(); }catch(e){}
    try{ if(typeof _mgTab!=='undefined' && _mgTab) renderMgTab(_mgTab); }catch(e){}
  }

  let _started=false;
  function startCloud(){
    if(_started) return; _started=true;
    window._fbReady = true; _setDot(true);
    FB_KEYS.forEach(key=>{
      try{
        db.ref('cockpit/'+key).on('value', snap=>{
          const val = snap.val();
          if(val===null){
            // Le cloud fait AUTORITÉ : s'il est vide pour cette clé, on vide AUSSI le local.
            // On NE ré-uploade JAMAIS le local vers le cloud. C'est ce ré-upload automatique
            // (ancienne "migration") qui faisait revenir les données — même après une suppression
            // via la console Firebase : l'app rouverte réécrivait aussitôt le cloud.
            const raw=localStorage.getItem(key);
            if(raw && raw!=='null' && raw!=='[]' && raw!=='{}'){ applyRemote(key, /^\s*\{/.test(raw)?{}:[]); }
            return;
          }
          if(JSON.stringify(val)===localStorage.getItem(key)) return; // inchangé / écho de notre propre écriture
          applyRemote(key, val);
        });
      }catch(e){}
    });
    // Signal de purge totale : si un poste clique sur « Tout supprimer », tous les postes
    // actuellement ouverts se RECHARGENT (récupèrent le code à jour + le cloud vidé) → aucune
    // réinjection possible. On ne réagit qu'aux purges survenues APRÈS le chargement de ce poste.
    const _bootTs = Date.now();
    try{
      db.ref('cockpit/_wipe').on('value', s=>{
        const t = +(s.val()||0);
        if(t > _bootTs){
          try{ toast('Données supprimées — rechargement…'); }catch(e){}
          setTimeout(()=>{ try{ location.reload(); }catch(e){} }, 900);
        }
      });
    }catch(e){}
  }

  function doLogin(){
    const em=(($f('fbEmail')||{}).value||'').trim(), pw=(($f('fbPass')||{}).value||'');
    if(!em||!pw){ _fbErr('Saisis ton e-mail et ton mot de passe.'); return; }
    _fbErr(''); const b=$f('fbBtn'); if(b){ b.disabled=true; b.textContent='Connexion…'; }
    auth.signInWithEmailAndPassword(em,pw).catch(err=>{
      const M={
        'auth/invalid-email':"E-mail invalide.",
        'auth/user-disabled':"Ce compte est désactivé.",
        'auth/user-not-found':"Aucun compte pour cet e-mail.",
        'auth/wrong-password':"Mot de passe incorrect.",
        'auth/invalid-credential':"Identifiants incorrects.",
        'auth/too-many-requests':"Trop de tentatives. Réessaie dans quelques minutes.",
        'auth/network-request-failed':"Problème réseau — vérifie ta connexion."
      };
      _fbErr(M[err.code] || ("Erreur : "+(err.code||err.message)));
    }).finally(()=>{ const bb=$f('fbBtn'); if(bb){ bb.disabled=false; bb.textContent='Se connecter'; } });
  }
  (function wire(){
    const b=$f('fbBtn'); if(b) b.addEventListener('click', doLogin);
    const p=$f('fbPass'); if(p) p.addEventListener('keydown', e=>{ if(e.key==='Enter') doLogin(); });
    const e=$f('fbEmail'); if(e) e.addEventListener('keydown', ev=>{ if(ev.key==='Enter'){ const pp=$f('fbPass'); if(pp) pp.focus(); } });
    const so=$f('fbSignOut'); if(so) so.addEventListener('click', ()=>{ if(confirm('Se déconnecter du Quality Cockpit ?')) auth.signOut(); });
  })();

  /* ====================== GESTION DES COMPTES & ACCÈS ======================
     Le SDK navigateur permet : créer un compte, envoyer un lien de réinit,
     changer SON propre mot de passe. Il ne peut PAS lister/supprimer les autres
     comptes (réservé à l'Admin SDK serveur) → on tient un registre dans RTDB
     (/accounts/{uid}) et on désactive l'accès via un drapeau appliqué à la connexion.
     Astuce clé : la création passe par une app Firebase SECONDAIRE pour ne pas
     déconnecter l'administrateur courant. */
  const ADMIN_EMAILS = ["admin@leoni.com", "simba@leoni.com"];   // ← AJOUTE ICI tes e-mails d'admin « racine » (accès total, non modifiable via la matrice de rôles)
  let _isAdmin=false, _myAccount=null, _accounts={};

  let _sec=null;
  function _secAuth(){
    if(!_sec){
      _sec = firebase.initializeApp(firebase.app().options, 'fbSecondary');
      try{ _sec.auth().setPersistence(firebase.auth.Auth.Persistence.NONE); }catch(e){}
    }
    return _sec.auth();
  }
  function _emailOK(e){ return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e); }
  function _acMsg(t,ok){ const m=$f('acMsg'); if(m){ m.textContent=t||''; m.className='ac-msg '+(ok?'ok':(t?'err':'')); m.style.display=t?'block':'none'; } }

  function ensureSelfAccount(user, registryEmpty){
    return db.ref('accounts/'+user.uid).once('value').then(snap=>{
      let rec=snap.val();
      if(!rec){
        const seed = ADMIN_EMAILS.includes((user.email||'').toLowerCase()) || registryEmpty;
        rec={ email:user.email||'', name:(user.displayName||''), role:seed?'admin':'utilisateur', qrole:'utilisateur', disabled:false, createdAt:Date.now(), createdBy:'(auto)' };
        try{ db.ref('accounts/'+user.uid).set(rec); }catch(e){}
      }
      return rec;
    }).catch(()=>({ email:user.email||'', role:'utilisateur', disabled:false }));
  }

  function renderAccounts(){
    const box=$f('acList'); if(!box) return;
    const uids=Object.keys(_accounts||{});
    if(!uids.length){ box.innerHTML='<div class="ac-empty">Aucun compte enregistré pour l’instant. Crée le premier ci-dessus.</div>'; return; }
    uids.sort((a,b)=>((_accounts[a].email||'').localeCompare(_accounts[b].email||'','fr')));
    const me = auth.currentUser ? auth.currentUser.uid : '';
    box.innerHTML = uids.map(uid=>{
      const a=_accounts[uid]||{}; const dis=a.disabled===true; const isAdm=a.role==='admin';
      const qrole=a.qrole||'utilisateur';
      const selVal=isAdm?'admin':qrole;
      const badgeLabel=isAdm?'Admin':(QROLE_LABELS[qrole]||'Utilisateur');
      const roleOpts=['utilisateur','manager','technicien','tl','admin'].map(v=>{
        const label=v==='admin'?'Admin':(v==='utilisateur'?'Utilisateur':QROLE_LABELS[v]);
        return '<option value="'+v+'"'+(selVal===v?' selected':'')+'>'+label+'</option>';
      }).join('');
      return '<div class="ac-row'+(dis?' ac-dis':'')+'">'
        +'<div class="ac-main"><div class="ac-mail">'+_esc(a.email||'—')+(uid===me?' <span class="ac-you">vous</span>':'')+'</div>'
        +'<div class="ac-meta"><span class="ac-badge '+(isAdm?'adm':'usr')+'">'+_esc(badgeLabel)+'</span>'
        +'<span class="ac-state">'+(dis?icon('close',12)+' désactivé':icon('check',12)+' actif')+'</span></div></div>'
        +'<div class="ac-act">'
        +'<select data-acqrole="'+uid+'" title="Rôle du compte" class="ac-qrole-sel">'+roleOpts+'</select>'
        +'<button data-acreset="'+uid+'" title="Envoyer un lien de réinitialisation du mot de passe">'+icon('key',12)+' Mot de passe</button>'
        +'<button data-acdis="'+uid+'" title="Activer / désactiver l’accès">'+(dis?'Activer':'Désactiver')+'</button>'
        +'<button data-acdel="'+uid+'" class="ac-del" title="Retirer du registre" aria-label="Retirer ce compte du registre">'+icon('trash',12)+'</button>'
        +'</div></div>';
    }).join('');
  }
  function _esc(s){ return String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c])); }

  function createAccount(){
    if(!_isAdmin){ _acMsg('Action réservée aux administrateurs.'); return; }
    const em=(($f('acEmail')||{}).value||'').trim().toLowerCase();
    const pw=(($f('acPass')||{}).value||'');
    const nm=(($f('acName')||{}).value||'').trim();
    const sel=(($f('acRole')||{}).value||'utilisateur');
    const rl = sel==='admin' ? 'admin' : 'utilisateur';
    const qrole = sel==='admin' ? 'utilisateur' : sel;
    if(!_emailOK(em)){ _acMsg('E-mail invalide.'); return; }
    if(pw.length<6){ _acMsg('Le mot de passe doit faire au moins 6 caractères.'); return; }
    const b=$f('acCreate'); if(b){ b.disabled=true; b.textContent='Création…'; } _acMsg('');
    const sa=_secAuth();
    sa.createUserWithEmailAndPassword(em,pw).then(cred=>{
      const uid=cred.user.uid;
      const rec={ email:em, name:nm, role:rl, qrole:qrole, disabled:false, createdAt:Date.now(), createdBy:(auth.currentUser&&auth.currentUser.email)||'' };
      return db.ref('accounts/'+uid).set(rec).then(()=>{ try{ sa.signOut(); }catch(e){} });
    }).then(()=>{
      _acMsg('Compte créé : '+em+(rl==='admin'?' (Admin)':' ('+(QROLE_LABELS[qrole]||qrole)+')'), true);
      ['acEmail','acPass','acName'].forEach(id=>{ const el=$f(id); if(el) el.value=''; });
    }).catch(err=>{
      try{ sa.signOut(); }catch(e){}
      const M={'auth/email-already-in-use':"Un compte existe déjà avec cet e-mail.",'auth/invalid-email':"E-mail invalide.",'auth/weak-password':"Mot de passe trop faible (min. 6 caractères).",'auth/operation-not-allowed':"Active d’abord « E-mail/Mot de passe » dans Firebase Authentication."};
      _acMsg(M[err.code]||("Erreur : "+(err.code||err.message)));
    }).finally(()=>{ const bb=$f('acCreate'); if(bb){ bb.disabled=false; bb.textContent='Créer le compte'; } });
  }

  function _acAction(e){
    const t=e.target.closest('button'); if(!t) return;
    if(!_isAdmin){ _acMsg('Action réservée aux administrateurs.'); return; }
    let uid;
    if((uid=t.getAttribute('data-acreset'))){
      const a=_accounts[uid]; if(!a||!a.email) return;
      auth.sendPasswordResetEmail(a.email).then(()=>_acMsg('Lien de réinitialisation envoyé à '+a.email, true)).catch(err=>_acMsg('Échec envoi : '+(err.code||err.message)));
    } else if((uid=t.getAttribute('data-acdis'))){
      const a=_accounts[uid]; if(!a) return;
      const nv=!(a.disabled===true);
      db.ref('accounts/'+uid+'/disabled').set(nv).then(()=>_acMsg(nv?'Accès désactivé (déconnexion au prochain chargement).':'Accès réactivé.', true)).catch(err=>_acMsg('Erreur : '+(err.code||err.message)));
    } else if((uid=t.getAttribute('data-acdel'))){
      const a=_accounts[uid]||{};
      if(!confirm("Retirer « "+(a.email||uid)+" » du registre ?\n\nNote : le login Firebase n’est PAS supprimé (l’utilisateur peut encore se connecter). Pour révoquer réellement l’accès, utilise « Désactiver », ou supprime le compte dans la console Firebase.")) return;
      db.ref('accounts/'+uid).remove().then(()=>_acMsg('Compte retiré du registre.', true)).catch(err=>_acMsg('Erreur : '+(err.code||err.message)));
    }
  }

  function _acQRoleChange(e){
    const sel=e.target.closest('[data-acqrole]'); if(!sel) return;
    if(!_isAdmin){ _acMsg('Action réservée aux administrateurs.'); renderAccounts(); return; }
    const uid=sel.getAttribute('data-acqrole'), v=sel.value;
    const role = v==='admin' ? 'admin' : 'utilisateur';
    const qrole = v==='admin' ? 'utilisateur' : v;
    db.ref('accounts/'+uid).update({role:role, qrole:qrole})
      .then(()=>_acMsg('Rôle mis à jour : '+(role==='admin'?'Admin':(QROLE_LABELS[qrole]||qrole)), true))
      .catch(err=>_acMsg('Erreur : '+(err.code||err.message)));
  }

  function changeMyPassword(){
    const np=(($f('acMyPass')||{}).value||'');
    if(np.length<6){ _acMsg('Le nouveau mot de passe doit faire au moins 6 caractères.'); return; }
    const u=auth.currentUser; if(!u) return;
    u.updatePassword(np).then(()=>{ _acMsg('Votre mot de passe a été changé.', true); const el=$f('acMyPass'); if(el) el.value=''; })
      .catch(err=>{ _acMsg(err.code==='auth/requires-recent-login' ? 'Pour des raisons de sécurité, déconnecte-toi puis reconnecte-toi avant de changer ton mot de passe.' : ('Erreur : '+(err.code||err.message))); });
  }

  function openAccounts(){ const m=$f('acModal'); if(m){ m.style.display='flex'; renderAccounts(); try{ renderRolePerms(); }catch(e){} _acMsg(''); } }
  function closeAccounts(){ const m=$f('acModal'); if(m) m.style.display='none'; }
  (function wireAccounts(){
    const a=$f('fbAccounts'); if(a) a.addEventListener('click', openAccounts);
    const x=$f('acClose'); if(x) x.addEventListener('click', closeAccounts);
    const bg=$f('acModal'); if(bg) bg.addEventListener('click', e=>{ if(e.target===bg) closeAccounts(); });
    const c=$f('acCreate'); if(c) c.addEventListener('click', createAccount);
    const list=$f('acList'); if(list){ list.addEventListener('click', _acAction); list.addEventListener('change', _acQRoleChange); }
    const mp=$f('acMyBtn'); if(mp) mp.addEventListener('click', changeMyPassword);
  })();

  let _acWatching=false;
  function watchAccounts(){
    if(_acWatching) return; _acWatching=true;
    try{
      db.ref('accounts').on('value', snap=>{
        _accounts = snap.val()||{};
        const u=auth.currentUser;
        if(u){
          _myAccount = _accounts[u.uid] || _myAccount;
          _isAdmin = ADMIN_EMAILS.includes((u.email||'').toLowerCase()) || (_myAccount && _myAccount.role==='admin') || Object.keys(_accounts).length===0;
          window._isAdmin=_isAdmin; window._myAccount=_myAccount;
          window._isSuperAdmin = ADMIN_EMAILS.includes((u.email||'').toLowerCase());
          const ab=$f('fbAccounts'); if(ab) ab.style.display=_isAdmin?'':'none';
          // révocation à chaud : si on désactive mon propre compte, je suis déconnecté
          if(_myAccount && _myAccount.disabled===true){ try{ auth.signOut(); }catch(e){} }
          try{ applyAccessGates(); }catch(e){}
        }
        const m=$f('acModal'); if(m && m.style.display!=='none'){ renderAccounts(); try{ renderRolePerms(); }catch(e){} }
      });
    }catch(e){}
  }

  /* ---------- état d'authentification (étendu : disabled + admin + comptes) ---------- */
  auth.onAuthStateChanged(function(user){
    if(user){
      db.ref('accounts').once('value').then(s=>{
        const reg=s.val()||{};
        return ensureSelfAccount(user, Object.keys(reg).length===0);
      }).then(rec=>{
        _myAccount=rec;
        if(rec && rec.disabled===true){
          _fbErr('Accès désactivé. Contacte un administrateur.');
          const o=$f('fbLogin'); if(o) o.style.display='flex';
          try{ auth.signOut(); }catch(e){}
          return;
        }
        _isAdmin = ADMIN_EMAILS.includes((user.email||'').toLowerCase()) || (rec && rec.role==='admin');
        window._isAdmin=_isAdmin; window._myAccount=_myAccount;
        window._isSuperAdmin = ADMIN_EMAILS.includes((user.email||'').toLowerCase());
        const o=$f('fbLogin'); if(o) o.style.display='none';
        const so=$f('fbSignOut'); if(so) so.style.display='';
        const ab=$f('fbAccounts'); if(ab) ab.style.display=_isAdmin?'':'none';
        try{ applyAccessGates(); }catch(e){}
        startCloud();
        watchAccounts();
      });
    }else{
      window._fbReady=false; _isAdmin=false; _myAccount=null;
      window._isAdmin=false; window._myAccount=null; window._isSuperAdmin=false;
      const so=$f('fbSignOut'); if(so) so.style.display='none';
      const ab=$f('fbAccounts'); if(ab) ab.style.display='none';
      const am=$f('acModal'); if(am) am.style.display='none';
      const o=$f('fbLogin'); if(o) o.style.display='flex';
      _setDot(false);
    }
  });
})();
/* ===================== FIN FIREBASE ===================== */

